args.sparql:
SELECT ?municipalityLabel ?mayorLabel WHERE {
  wd:Q16982514 wdt:P276 ?municipality .
  ?municipality rdfs:label ?municipalityLabel .
  ?municipality wdt:P3224 ?mayor .
  ?mayor rdfs:label ?mayorLabel .
}

SELECT ?mayor ?mayorLabel WHERE {
  wd:Q16982514 wdt:P276 ?municipality .
  ?municipality wdt:P6 ?mayor .
  ?mayor rdfs:label ?mayorLabel .
  FILTER(LANG(?mayorLabel) = 'en' || LANG(?mayorLabel) = 'pt')
}

SELECT ?mayorLabel WHERE {
  wd:Q941958 wdt:P6 ?mayor .
  ?mayor rdfs:label ?mayorLabel .
  FILTER(LANG(?mayorLabel) = 'en' || LANG(?mayorLabel) = 'pt')
}

SELECT ?venueLabel WHERE {
  wd:Q16982514 wdt:P276 ?venue.
  ?venue rdfs:label ?venueLabel.
  FILTER(LANG(?venueLabel) = 'en' || LANG(?venueLabel) = 'pt')
}
